const d = $json;
let diem = 0;
const logs = [];

// Chuyển khoản: 30đ
if (d.moTaChuyenKhoan && d.moTaChuyenKhoan.length > 10) {
  diem += 30; logs.push('✅ CK đầy đủ: +30');
} else { logs.push('❌ Thiếu mô tả chuyển khoản: 0'); }

// File HTML Messenger: 25đ
if (d.coHtmlMessenger && d.coHtmlMessenger.includes('Có')) {
  diem += 25; logs.push('✅ Có HTML Messenger: +25');
} else { logs.push('⚠️ Không có HTML Messenger: 0'); }

// Ảnh sản phẩm: 20đ
if (d.moTaSanPham && d.moTaSanPham.length > 10) {
  diem += 20; logs.push('✅ Có ảnh sản phẩm: +20');
} else { logs.push('❌ Thiếu ảnh sản phẩm: 0'); }

// File upload: 10đ
if (d.soFileUpload >= 3) {
  diem += 10; logs.push('✅ Upload ≥3 file: +10');
} else if (d.soFileUpload >= 1) {
  diem += 5; logs.push('⚠️ Upload ít file: +5');
} else { logs.push('❌ Không upload file: 0'); }

// Drive folder: 10đ
if (d.linkDriveFolder && d.linkDriveFolder.startsWith('http')) {
  diem += 10; logs.push('✅ Có Drive link: +10');
} else { logs.push('❌ Không có Drive link: 0'); }

// Ngày GD: 5đ
if (d.ngayGdDauTien && d.ngayGdCuoi) {
  diem += 5; logs.push('✅ Có ngày GD: +5');
}

// Xếp loại
let xepLoai;
if (diem >= 70 && d.coHtmlMessenger && d.coHtmlMessenger.includes('Có')) {
  xepLoai = 'A';
} else if (diem >= 50) {
  xepLoai = 'B';
} else if (diem >= 30) {
  xepLoai = 'C';
} else {
  xepLoai = 'X';
}

// Cảnh báo
const canhBao = [];
if (parseFloat(d.phanTramKN) > 100) canhBao.push('Tiền KN > Tổng tiền mua');
if (d.tinhTrangBC && d.tinhTrangBC.includes('Đầy đủ') && d.soFileUpload < 3) {
  canhBao.push('Tự khai đầy đủ nhưng upload ít file');
}
if (d.tongTienKhieuNai > 50000000) canhBao.push('Số tiền lớn >50tr');

const canReview = canhBao.length > 0 || xepLoai === 'X';
const tomTat = `${d.hoTen||'N/A'} | ${d.tinhThanh||''} | ${Number(d.tongTienKhieuNai||0).toLocaleString('vi-VN')}đ | Nhóm ${xepLoai}`;

return [{ json: {
  ...d,
  diemBC: diem,
  xepLoai,
  chiTietPhanTich: logs.join('\n'),
  canhBao: canhBao.length > 0 ? '⚠️ ' + canhBao.join(' | ') : '—',
  canReviewThuCong: canReview ? 'TRUE' : 'FALSE',
  tomTat,
  diemUuTien: diem
}}];
